import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';
import { motion } from 'framer-motion';

const TrendingTicker = () => {
  const [tickerItems, setTickerItems] = useState([]);

  useEffect(() => {
    fetchTickerItems();
    const interval = setInterval(fetchTickerItems, 30000);
    return () => clearInterval(interval);
  }, []);

  const fetchTickerItems = async () => {
    const { data: proposals } = await supabase
      .from('proposals')
      .select('id, title, support_count')
      .eq('status', 'approved')
      .order('support_count', { ascending: false })
      .limit(10);

    if (proposals) {
      const items = proposals.map(p => ({
        id: p.id,
        text: `📢 ${p.title} – ${p.support_count || 0} soutiens`
      }));
      setTickerItems(items);
    }
  };

  const tickerContent = [...tickerItems, ...tickerItems, ...tickerItems];

  return (
    <div className="ticker-container">
      <div className="ticker-label">À LA UNE</div>
      <div className="ticker-track">
        <motion.div
          className="ticker-content"
          animate={{ x: [0, -2000] }}
          transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
        >
          {tickerContent.map((item, idx) => (
            <span key={idx} className="ticker-item">
              {item.text}
            </span>
          ))}
        </motion.div>
      </div>
    </div>
  );
};

export default TrendingTicker;
